const formItem = $('1. Form — Portfolio Request').first().json;
const rows     = $input.first().json.holdings || [];

const investorName  = (formItem['Your Full Name']    || '').trim();
const investorEmail = (formItem['Your Email Address']|| '').trim();
const portfolioName = (formItem['Portfolio Name']    || 'My Portfolio').trim();
const currency      = (formItem['Base Currency']     || 'USD').split('—')[0].trim();
const notes         = (formItem['Notes for Analyst'] || '').trim();
const analyzedAt    = new Date().toISOString();

if (!investorEmail) throw new Error('Investor email missing from form.');
if (!rows || rows.length === 0) {
  throw new Error(
    'No holdings found in Google Sheet tab "Portfolio". ' +
    'Make sure tab name is exactly "Portfolio" and columns are: ' +
    'ticker, company, sector, asset_class, quantity, avg_buy_price, current_price'
  );
}

const norm = (v) => (v ?? '').toString().trim();

const holdings = rows.map(r => {
  const qty      = parseFloat(r.quantity)      || 0;
  const avgBuy   = parseFloat(r.avg_buy_price) || 0;
  const curPrice = parseFloat(r.current_price) || 0;
  const mktVal   = qty * curPrice;
  const costBasis= qty * avgBuy;
  const pnl      = mktVal - costBasis;
  const pnlPct   = costBasis > 0 ? (pnl / costBasis) * 100 : 0;
  return {
    ticker:      norm(r.ticker      || r.Ticker     || r.symbol || 'UNKNOWN'),
    company:     norm(r.company     || r.Company    || r.ticker || ''),
    sector:      norm(r.sector      || r.Sector     || 'Unclassified'),
    assetClass:  norm(r.asset_class || r.AssetClass || 'Equity'),
    quantity:    qty,
    avgBuyPrice: avgBuy,
    currentPrice:curPrice,
    marketValue: +mktVal.toFixed(2),
    costBasis:   +costBasis.toFixed(2),
    pnl:         +pnl.toFixed(2),
    pnlPct:      +pnlPct.toFixed(2)
  };
}).filter(h => h.ticker !== 'UNKNOWN' && h.marketValue > 0);

if (holdings.length === 0) {
  throw new Error('All rows filtered out — check that quantity and current_price columns have numeric values greater than 0.');
}

const totalValue = holdings.reduce((s, h) => s + h.marketValue, 0);
const totalCost  = holdings.reduce((s, h) => s + h.costBasis, 0);
const totalPnl   = totalValue - totalCost;
const totalPnlPct= totalCost > 0 ? (totalPnl / totalCost) * 100 : 0;

const holdingsWithAlloc = holdings.map(h => ({
  ...h,
  allocPct: totalValue > 0 ? +((h.marketValue / totalValue) * 100).toFixed(2) : 0
}));

const sectorMap = {};
holdingsWithAlloc.forEach(h => {
  if (!sectorMap[h.sector]) sectorMap[h.sector] = { value: 0, tickers: [] };
  sectorMap[h.sector].value += h.marketValue;
  sectorMap[h.sector].tickers.push(h.ticker);
});
const sectorBreakdown = Object.entries(sectorMap)
  .map(([sector, d]) => ({
    sector,
    marketValue:  +d.value.toFixed(2),
    allocPct:     totalValue > 0 ? +((d.value / totalValue) * 100).toFixed(2) : 0,
    tickers:      d.tickers
  }))
  .sort((a, b) => b.allocPct - a.allocPct);

const acMap = {};
holdingsWithAlloc.forEach(h => {
  acMap[h.assetClass] = (acMap[h.assetClass] || 0) + h.marketValue;
});
const assetClassBreakdown = Object.entries(acMap)
  .map(([ac, val]) => ({
    assetClass: ac,
    marketValue: +val.toFixed(2),
    allocPct:   totalValue > 0 ? +((val / totalValue) * 100).toFixed(2) : 0
  }))
  .sort((a, b) => b.allocPct - a.allocPct);

const STOCK_THRESHOLD  = 15;
const SECTOR_THRESHOLD = 35;
const TOP3_THRESHOLD   = 60;

const overweightStocks  = holdingsWithAlloc.filter(h => h.allocPct > STOCK_THRESHOLD);
const overweightSectors = sectorBreakdown.filter(s => s.allocPct > SECTOR_THRESHOLD);
const top3Pct = [...holdingsWithAlloc]
  .sort((a, b) => b.marketValue - a.marketValue)
  .slice(0, 3)
  .reduce((s, h) => s + h.allocPct, 0);
const top3Risk = top3Pct > TOP3_THRESHOLD;

let riskScore = 0;
riskScore += Math.min(overweightStocks.length  * 10, 30);
riskScore += Math.min(overweightSectors.length * 15, 30);
riskScore += top3Risk ? 20 : 0;
riskScore += holdings.length < 5 ? 20 : (holdings.length < 10 ? 10 : 0);

const riskLabel = riskScore >= 60 ? 'HIGH' : riskScore >= 30 ? 'MEDIUM' : 'LOW';

const byPnlPct = [...holdingsWithAlloc].sort((a, b) => b.pnlPct - a.pnlPct);
const topGainers = byPnlPct.slice(0, 3).map(h => ({ ticker: h.ticker, pnlPct: h.pnlPct, pnl: h.pnl }));
const topLosers  = byPnlPct.slice(-3).reverse().map(h => ({ ticker: h.ticker, pnlPct: h.pnlPct, pnl: h.pnl }));

return [{
  json: {
    investorName,
    investorEmail,
    portfolioName,
    currency,
    notes,
    analyzedAt,
    summary: {
      totalValue:      +totalValue.toFixed(2),
      totalCost:       +totalCost.toFixed(2),
      totalPnl:        +totalPnl.toFixed(2),
      totalPnlPct:     +totalPnlPct.toFixed(2),
      holdingCount:    holdingsWithAlloc.length,
      riskScore,
      riskLabel
    },
    holdings:         holdingsWithAlloc,
    sectorBreakdown,
    assetClassBreakdown,
    riskFlags: {
      overweightStocks:  overweightStocks.map(h => ({ ticker: h.ticker, allocPct: h.allocPct })),
      overweightSectors: overweightSectors.map(s => ({ sector: s.sector, allocPct: s.allocPct })),
      top3Pct:           +top3Pct.toFixed(2),
      top3Risk,
      stockThreshold:    STOCK_THRESHOLD,
      sectorThreshold:   SECTOR_THRESHOLD
    },
    topGainers,
    topLosers
  }
}];

